INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027aa2e3c98b09417658c9', '中秋假期带家人出行，入住了美丽的花园酒店，得到了用心用情的照顾，全家人都十分满意。特此感谢根据我们需求帮我们办理入住的Cassie女士，感谢带我们参观游览26个打卡点的金牌导览Hohn先生，感谢为我们送上手写信件和中秋月饼的客房房口部迎送岗 Adeline女士。你们的专业非常值得称颂，下次来广州，一定会再次入住的。也祝你们中秋节快乐！', '["https://dimg04.c-ctrip.com/images/0230712000flteukz90C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 168, 0, 6, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027aa2e3c98b09417658ca', '房间64平，宽敞。服务热情周到。环境优美，装修大气，作为白金五星酒店性价比很高，出行方便，只要不去长隆玩，离广州所有玩的地方，像永庆坊，陈家祠，海心沙，沙面，北京路，圣心大教堂，珠江夜游都不远。', '["https://dimg04.c-ctrip.com/images/0231812000f321zrj345B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000f31ztkxC777_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000f31tqn496AD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-11', '红棉大床套房', '套房', '家庭亲子', 97, 0, 2, 9, '["性价比","交通便利性","整体满意度"]'::jsonb, '性价比', '交通便利性', '整体满意度'),
('68027aa2e3c98b09417658cb', '酒店已经三十九年了，但很多硬件设施还是很好，工作人员的服务也很棒！特别30楼行政酒廊的Carrie，Kitty和Rose，服务热情周到，赞！', '["https://dimg04.c-ctrip.com/images/0230u12000flu74q9C853_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000flu1ni4E4BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000flu4wrz6A58_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 70, 0, 5, 8, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68027aa2e3c98b09417658cc', '酒店很有历史厚重感，大堂很气派也维护地很好，房间偏小但是重新装修后挺温馨，泳池桑拿冰水池等等设施很完善，床品枕头都很舒服合适，墙面柜子个别地方有点点发霉的地方可以加强维护，另外还有漂亮小花园和酒店博物馆整个入住的体验都很愉快休闲放松。', '["https://dimg04.c-ctrip.com/images/0235v12000f056674CEEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000f053jox6DF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000f050bk57E57_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2024-08-04', '花园双床房', '双床房', '朋友出游', 117, 1, 5, 9, '["公共设施","整体满意度","房间设施"]'::jsonb, '公共设施', '整体满意度', '房间设施'),
('68027aa2e3c98b09417658cd', '对花园品牌从未失望，广州花园酒店更是意外之惊喜！感谢贴心客房管家，热情的客房清扫员，和一楼瀑布餐厅，30F酒廊的优质餐食，下次来广州依然会选择花园酒店！', '["https://dimg04.c-ctrip.com/images/0230712000fi6ypjr45BB_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231012000fi6zxe7BEBD_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-11', '花园大床房', '大床房', '商务出差', 76, 0, 11, 7, '["客房服务","餐饮设施","整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度'),
('68027aa2e3c98b09417658ce', '第一次入住传说中的白金六星级酒店，其他两家都住过；环境确实被惊艳到了，房间也很棒，行政酒廊的早餐非常棒，只是早餐厅服务员的态度就很牵强了，没有亲和力的服务，站门口对客人也是不理不睬的，这点是有待提升的', '["https://dimg04.c-ctrip.com/images/0232x12000gbemno4D118_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000gbecnmc18F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000gbemno69D25_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-25', '花园大床房', '大床房', '商务出差', 100, 0, 82, 8, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027aa2e3c98b09417658cf', '特别好的酒店，每一个人都很专业。服务热情周到。房间干净整洁。娃的玩具临走之前落在了酒店房间里，打电话给酒店，也给找到并且快递到家了。酒店地理位置也很好。', '["https://dimg04.c-ctrip.com/images/02316224x8wa2umuaD4D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02316224x8wa2x5bp0601_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h224x8wa2m638D455_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02361224x8wa2sw4x6935_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-08', '花园双床房', '双床房', '家庭亲子', 76, 0, 2, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027aa2e3c98b09417658d0', '环境很好，特别是大厅很大气，而且服务态度都很好！非常感谢Ariel.winnie.kitty.三人都很专业，笑容甜美，看到带了孩子还帮升级了房间，孩子玩得很开心，下次来还会入住', '["https://dimg04.c-ctrip.com/images/0233712000f6tbw3s9185_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000f6t9ihh672E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000f6tkatb5899_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000f6t4w2nBDF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-20', '花园双床房', '双床房', '家庭亲子', 88, 0, 4, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027aa2e3c98b09417658d1', '一走近大堂就可以用金碧辉煌来形容，国庆假期价格也没有特别夸张，和隔壁的连锁酒店就相差了一百块左右，毫不犹豫选择了这家', '["https://dimg04.c-ctrip.com/images/0235012000gu2r1cl58A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000gu2l2w829A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000gu2phd472CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-23', '花园大床房', '大床房', '情侣出游', 58, 0, 3, 5, '["性价比","整体满意度"]'::jsonb, '性价比', '整体满意度', NULL),
('68027aade3c98b09417658d2', '广州花园酒店人气很足，是老牌五星级酒店。交通方便，房间干净卫生，早餐丰富。Cecilia很热情，服务很好，还免费升级了房型，太满意了！下次来广州还住花园酒店！', '["https://dimg04.c-ctrip.com/images/0232k224x8w7x6e0816FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q224x8w7vwtey816C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r224x8w7xuf91C829_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-04', '花园大床房', '大床房', '商务出差', 79, 0, 16, 8, '["整体满意度","交通便利性","卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况'),
('68027aade3c98b09417658d3', '每次出差都特别喜欢住花园酒店，无论是地理位置，卫生条件，尤其是服务水平，在这里要特别表扬前台接待Mancy，态度热情周到，业务也非常熟练，下次出差还是会选择住花园酒店！', '["https://dimg04.c-ctrip.com/images/0234p12000juou628F3EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000jup95sxD785_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-16', '花园大床房', '大床房', '商务出差', 84, 0, 23, 8, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68027aade3c98b09417658d4', '五星级酒店 就是方方面面都具到
服务 硬体 都是恰如其分的五星等级
下次还是要来住', '["https://dimg04.c-ctrip.com/images/0233m12000ggvairoA167_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231612000ggvabd0AA93_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231412000ggva7x48D94_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232q12000ggvafzw0154_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-11-03', '花园大床房', '大床房', '商务出差', 41, 0, 1, 5, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027aade3c98b09417658d5', '接待热情周到！客房服务细心！设施略显老旧但依旧掩饰不住老牌五星级酒店的风采！下次再来时期望能给我留下更美丽的印象！', '["https://dimg04.c-ctrip.com/images/0237112000fyxoy7u061A_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231t12000fyxlr3u8057_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236r12000fyxlphr52DF_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232c12000fyxlphx1B4C_R_150_150_R5_Q70_D.png"]'::jsonb, 4.7, 4, '2024-10-04', '花园双床房', '双床房', '家庭亲子', 57, 0, 10, 6, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027aade3c98b09417658d6', '这次的旅程很满意，在花园酒店入住很愉快，并且这里的服务很好，在行政酒廊里Mira Beryle和Cathy的服务态度的都很不错，这里很环境景色都不错。', '["https://dimg04.c-ctrip.com/images/0230912000fe0sf8t3A18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000fe0l74n3652_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-04', '花园双床房', '双床房', '家庭亲子', 75, 0, 1, 7, '["前台服务","整体满意度","景观/朝向"]'::jsonb, '前台服务', '整体满意度', '景观/朝向'),
('68027aade3c98b09417658d7', '房间设施完备，入住客人可以在地库免费停车。酒店后面的花园之大超乎我的预期。行政酒廊的Carry服务热情周到。早餐也不错。
下次来羊城还会选择这里', '["https://dimg04.c-ctrip.com/images/0232u12000gugml6j9E32_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000guh7jfsB9A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000guh9y3x1766_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-24', '花园大床房', '大床房', '情侣出游', 72, 0, 12, 7, '["房间设施","公共设施","餐饮设施"]'::jsonb, '房间设施', '公共设施', '餐饮设施'),
('68027aade3c98b09417658d8', '服务很好，免费升级了套房，行政酒廊的Kan Chan, Deepa, Beryle, Mira都很nice，下午茶和欢乐时光都很丰盛，整体入住体验非常好！值得推荐！', '["https://dimg04.c-ctrip.com/images/0232u12000fa0v4h78BB6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000fa17gciCA16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000fa15k7y2B38_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 82, 0, 1, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027aade3c98b09417658d9', '这次在酒店的入住体验真的格外舒心，前台 Betty 和礼宾 Roy 提供的优质服务给我
 前台 Betty办理入住手续时，她的操作既熟练又迅速，每一个环节都耐心细致地为我们讲解，还主动告知酒店的各项设施以及相关注意事项，让初来乍到的我们对接下来的住宿安排一清二楚。而且，无论我们提出什么样的问题，她总是能第一时间给予专业且周到的解答，那种耐心和热情自始至终都没有丝毫减退，哪怕是面对酒店入住高峰期，她也能有条不紊地应对每一位宾客，服务质量丝毫不打折扣，真的特别让人钦佩。还有礼宾 Roy，他同样给我们留下了深刻的印象。刚到酒店门口，Roy 就热情地迎了上来，主动帮忙拿行李，动作十分麻利又小心翼翼，让人感觉自己的物品被妥善照顾着。在引导我们前往房间的途中，他还一路热情地介绍酒店的特色之处，让这段路程变得轻松又愉快。不仅如此，在我们后续出行需要帮忙叫车或者咨询周边景点信息时，Roy 也总是能迅速给出实用的建议，帮忙安排得妥妥当当。
 谢谢 Betty 和 Roy 用他们的专业素养、热情态度以及无微不至的服务，为我们打造了一次难忘的酒店入住体验，也期待下次再来。', '["https://dimg04.c-ctrip.com/images/0230e12000jehevkx783A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000jehtj558655_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-29', '花园大床房', '大床房', '朋友出游', 482, 0, 2, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027aade3c98b09417658da', '酒店金卡会员升级了房间，前台Arrie和Wnnie服务挺好的。行政酒廊Carrie和Echo很热情，欢乐时光比下午茶多东西吃，房间确实是有一些年份了，很干净，但也有一些老化的部分。总的来说还是很不错的，下次再来。美中不足的是入住时没人帮忙拿行李，五星级酒店不应该啊！', '["https://dimg04.c-ctrip.com/images/0236312000exoioif04FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000exojurg18A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000exo90xg2A69_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000exo2ohbAA0C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-07-29', '花园大床房', '大床房', '情侣出游', 133, 0, 8, 7, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027ab9e3c98b09417658dc', '四年前住过这次来广州还是入住了这家酒店，本来是会员可以升房间的但是十一期间房间很紧张没有给我升房间，但是送了3天的早餐，特别要说一下客房服务员刘美丽很贴心因为天气热每天都会给我们补充足够的饮用水。', '["https://dimg04.c-ctrip.com/images/0235w12000g0czwnnD114_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000g0dbdfr19AF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000g0d38teAD76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000g0d4zf6300D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-06', '花园双床房', '双床房', '家庭亲子', 98, 0, 8, 8, '["客房服务","餐饮设施"]'::jsonb, '客房服务', '餐饮设施', NULL),
('68027ab9e3c98b09417658dd', '历史悠久的酒店，深藏着文化底蕴。门面气派，环境一流，服务也特别好，很热情粤韵大床套房很新很干净，住了很舒服。', '["https://dimg04.c-ctrip.com/images/0234h12000g1jcm2t14BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000g1jjmmb3EF5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000g1jit7e1624_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000g1j9h0s3223_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000g1j0wep06C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000g1jayedC4ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-08', '花园双床房', '双床房', '家庭亲子', 54, 0, 3, 6, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68027ab9e3c98b09417658de', '这次来广州听取老婆意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，太nice了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。', '["https://dimg04.c-ctrip.com/images/0234i12000exgcemkC897_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000exfkbztB6D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000exfzfqx1270_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-28', '花园大床房', '大床房', '家庭亲子', 113, 0, 6, 7, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027ab9e3c98b09417658df', '酒店处于市中心  交通便利  打车方便  门口就是地铁环境非常优美  到处都是好闻的香味  酒店管理非常到位  服务热情周到  房间床品非常舒适  房间设施唯一不足是卫浴半开放  洗澡要跨进浴缸  和厕所的门是公用移门  使用起来有点尴尬  酒店早餐非常丰盛  品种很多  酒店内也有几个特色餐厅  看上去也不错', '["https://dimg04.c-ctrip.com/images/0234w12000eysjcn508F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-08-01', '花园双床房', '双床房', '朋友出游', 156, 0, 6, 8, '["交通便利性","房间设施","餐饮设施"]'::jsonb, '交通便利性', '房间设施', '餐饮设施'),
('68027ab9e3c98b09417658e0', '服务员兰英
服务热情、周到，看到酒店送的花后，主动拿来了花瓶插好，并写了一张热心卡片。', '["https://dimg04.c-ctrip.com/images/0232812000h6332b16778_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-12', '花园双床房', '双床房', '其他', 43, 0, 20, 8, '["客房服务"]'::jsonb, '客房服务', NULL, NULL),
('68027ab9e3c98b09417658e1', '广州老牌酒店 很大 还有很多类型的餐厅。还有米其林二星西餐厅。 赶上广交会 好多友人入住', '["https://dimg04.c-ctrip.com/images/0234912000gbs1ypz7615_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000gbrf9vj7181_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-26', '花园大床房', '大床房', '商务出差', 44, 0, 9, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027ab9e3c98b09417658e2', '太满意??啦 到达前管家Rita就开始联系我 为我推荐餐厅和服务 到达后前台给免费升级了套房 最满意的是大床 睡了一个好觉 下次一定会继续入住的！', '["https://dimg04.c-ctrip.com/images/0232j12000fg3ctrz2C7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000fg3v9dwC2F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000fg3r7c7A846_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000fg3ihlj5F7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000fg3r7crFE80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000fg3e1e7E06C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-07', '花园大床房', '大床房', '商务出差', 73, 0, 36, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68027ab9e3c98b09417658e3', '订的红棉套房套餐。优惠较多，性价比极好。3楼桃园餐厅菜品不错，但价格有些贵，但套餐送了些餐券儿，还好。服务人员很nice。', '["https://dimg04.c-ctrip.com/images/0234212000g04etw24DF0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000g046zst3B38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000g041a6d4F0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-06', '红棉大床套房', '套房', '家庭亲子', 61, 0, 15, 7, '["性价比","餐饮设施","前台服务"]'::jsonb, '性价比', '餐饮设施', '前台服务'),
('68027ab9e3c98b09417658e4', '酒店位置不好，周围吃饭选择很多，所有工作人员都很热情，会主动打招呼，礼宾部Eva服务很好很热情。酒店早餐也不错，品质很高，房间是有点老了，但是维护的还不错', '["https://dimg04.c-ctrip.com/images/0232s12000jlsgb8p7051_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '花园双床房', '双床房', '家庭亲子', 77, 0, 31, 8, '["周边配套","前台服务","餐饮设施"]'::jsonb, '周边配套', '前台服务', '餐饮设施'),
('68027ab9e3c98b09417658e5', '这次是我第二次入住花园酒店，体验依旧无与伦比，必须给个满分好评！ 从前台办理入住起，前厅部副经理吴灵伶就展现出了非凡的专业与贴心。得知同行有老人家，她精心为我安排了安静舒适的房间，让我们一进酒店就感受到满满的关怀。到了房间，楼层服务员Adan更是细致入微，了解情况后迅速为我额外准备了几块地巾，以防老人滑倒，这一举动真的太暖心了。酒店房间设施设备一如既往地齐全，各种用品一应俱全，完全满足了我们的需求，每次入住都有喜出望外之感。 可没想到，3月25日晚上，家人生病了，情况紧急。酒店值班经理Yannis得知后，毫不犹豫地忙前忙后，安排人员带着老人家前往医院，一路悉心照料。礼宾部的罗家俊也不辞辛劳，专门陪同到医院，帮忙处理各种事务。他们的热情与担当，让慌乱中的我有了十足的安全感。真心感谢花园酒店的吴灵伶、Yannis、Adan、罗家俊，因为你们，让我在这异乡感受到了家一般的温暖，下次出行，我依然只选花园酒店！', '["https://dimg04.c-ctrip.com/images/0231y12000jc7inpfF826_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000jc80buj7CAB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000jc8bhea6CB4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-26', '花园大床房', '大床房', '家庭亲子', 406, 0, 1, 10, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027ac3e3c98b09417658e6', '广州花园酒店，环境优雅宜人。房间宽敞舒适，设施齐全。餐饮丰富美味，服务周到热情，是来广州住宿的绝佳之选。??', '["https://dimg04.c-ctrip.com/images/0231n12000g0djz7l0F07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000g0dmtfe712F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000g0duelqD8B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000g0dn06u879E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-06', '红棉大床套房', '套房', '家庭亲子', 54, 0, 3, 6, '["整体满意度","房间设施","餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施'),
('68027ac3e3c98b09417658e7', '酒店环境非常不错??是一座可以逛的酒店。地理位置优越，交通方便。工作人员热情主动，顶层的360度旋转餐厅吃早餐很惬意，有烟熏三文鱼，沙发有些脱皮了', '["https://dimg04.c-ctrip.com/images/0236d12000fd455di7257_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235z12000fd44ubi7308_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236c12000fd44izo1155_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231712000fd44d9fC1D6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232012000fd44ahi03AF_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-09-02', '花园大床房', '大床房', '家庭亲子', 73, 0, 4, 8, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('68027ac3e3c98b09417658e8', '不错，带娃床有点小。早餐很不错
连住2晚，一早瀑布餐厅，挺丰富的
第二天早上换桃园厅，阳光精致早餐
离地铁口很近，出门非常方便', '["https://dimg04.c-ctrip.com/images/0232s12000fltje3sFCC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000fltlj1kD2CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000flt8q572FE8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-09-17', '花园大床房', '大床房', '家庭亲子', 63, 0, 1, 7, '["餐饮设施","交通便利性","房间设施"]'::jsonb, '餐饮设施', '交通便利性', '房间设施'),
('68027ac3e3c98b09417658e9', '临时决定入住，酒店免费升档成套房。服务、环境和自助早餐一流，顺带参观了四楼的酒店博物馆，非常值得看看，了解下广州众多著名酒店的前世今生。', '["https://dimg04.c-ctrip.com/images/0230e12000ffxbttsED28_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000ffxrto9DCD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000ffxk9hh4A54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-07', '花园大床房', '大床房', '家庭亲子', 68, 0, 1, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027ac3e3c98b09417658ea', '交通方便，服务不错，房间小巧精致，4楼博物馆和花园小朋友很喜欢，打卡的活动小朋友也很喜欢，体验还不错。', '["https://dimg04.c-ctrip.com/images/0236012000fztdfxr4C6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000fzsxbkv6A91_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000fztcpij3CDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-10-05', '花园大床房', '大床房', '朋友出游', 51, 0, 2, 7, '["交通便利性","整体满意度","周边配套"]'::jsonb, '交通便利性', '整体满意度', '周边配套'),
('68027ac3e3c98b09417658eb', '酒店非常不错，好评，干净卫生，下次还会住这里，酒店服务人员态度也很热情，尤其是前台 非常周到，服务态度很好！！！！。', '["https://dimg04.c-ctrip.com/images/0231t12000fq6orzq0F4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000fq6dt84AF16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000fq6ol2kD407_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-24', '花园大床房', '大床房', '商务出差', 58, 0, 56, 6, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027ac3e3c98b09417658ec', 'kiki小姐姐的服务特别好，酒店房间很大，床品舒适，酒店后面的瀑布花园设计，很有特点。
酒店入住了很多外国人，早餐有小牛排，行政酒廊晚上的品类会多些。', '["https://dimg04.c-ctrip.com/images/0230k12000f9w5b38ACF8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000f9w4dm50DE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000f9vqdc1B1A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000f9vqk8w1F8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000f9vjfliF258_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000f9vxzglF3BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-27', '红棉双床套房', '套房', '朋友出游', 75, 0, 5, 8, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027ac3e3c98b09417658ed', '酒店很豪华 早餐在瀑布餐厅拍照超好看 房间的镜子照的人也瘦 行政酒廊的沙爹牛肉串好吃 服务也非常好！开始我还想老酒店设施会不会陈旧，结果完全不用担心！', '["https://dimg04.c-ctrip.com/images/0236x12000fb83z2lAA49_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000fb8cv042289_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000fb7xcql3D8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000fb7ngyw0156_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000fb7qtcn0E04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000fb85cmq927D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-30', '花园大床房', '大床房', '情侣出游', 75, 0, 13, 8, '["餐饮设施","整体满意度","房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施'),
('68027ac3e3c98b09417658ee', '楼层过道和房间内部都不错，干净整洁。早餐是套餐制的，可以品尝地道广州早茶。接待的小姐姐和小哥哥们也都非常热情。', '["https://dimg04.c-ctrip.com/images/0235y12000gicbryvD589_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000gicpfpr793D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000gicd8383366_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-05', '花园大床房', '大床房', '商务出差', 55, 0, 1, 7, '["卫生状况","餐饮设施","前台服务"]'::jsonb, '卫生状况', '餐饮设施', '前台服务'),
('68027ad3e3c98b09417658f0', '房间紧凑吧还好，住老酒店看重的是服务品质，晚上九点多到店，问前台可以免费升级房型吗？前台说客房已满了抱歉，可以送你四份早餐吗（我们是两个大人两个小孩），这突来的惊喜确实把我惊了一跳（早餐单价是2百多一点一位），第二天孩子要游泳，致电前台可以免费延时退房吗？前台回答可以的这边给你延时到两点退房，随后叫客房服务员拿件小孩浴衣，结果不仅拿了浴衣还拿了小孩的洗发水和沐浴露，这服务真是太贴心了，特别说一下这个酒店的游泳池很棒，泳池边的三个救生员让你能安心把孩子放在那里玩，还有免费的饮品喝哦。酒店门口随时有出租车等候，出行太方便，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0232e12000ewdl1uvEF5F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-07-25', '花园双床房', '双床房', '家庭亲子', 269, 1, 13, 9, '["前台服务","客房服务","公共设施"]'::jsonb, '前台服务', '客房服务', '公共设施'),
('68027ad3e3c98b09417658f1', '酒店环境非常赞????，尤其是后花园和博物馆，就是酒店的设施有点老旧，尤其是是插座要么插不上去，要么插上去了会松掉，还有大堂竟然没有可以坐的座位，不是很人性化', '["https://dimg04.c-ctrip.com/images/0233e12000f7jz33tF2E7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000f7jwskl7955_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000f7jmc66D9B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000f7jv9zaD477_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000f7jn4si10AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-08-22', '花园大床房', '大床房', '家庭亲子', 79, 0, 3, 8, '["房间设施","公共设施","整体满意度"]'::jsonb, '房间设施', '公共设施', '整体满意度'),
('68027ad3e3c98b09417658f2', '环境优美，服务态度很好', '["https://dimg04.c-ctrip.com/images/0230y12000hfaoalkDC7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000hfawjgw9F97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000hf9w40w18B3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-26', '花园大床房', '大床房', '情侣出游', 11, 0, 2, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027ad3e3c98b09417658f3', '????花园?行政酒廊特别表扬Echo,beryle,kanchan', '["https://dimg04.c-ctrip.com/images/0233w12000ggxxn9j89DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000ggy8p6tDB8B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-03', '城央绿意双床房', '双床房', '商务出差', 34, 0, 2, 2, '["餐饮设施","前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL),
('68027ad3e3c98b09417658f4', '老牌的五星酒店，虽然年代久远，却维护得很好，只是房间狭小，设施陈旧，房间空间矮，这个没办法，硬伤，但是酒店环境挺好，楼上的博物馆值得看看。先说入住，没有半个小时也有二十分钟，等得太久了，小姐姐一人送了两只康乃馨表示歉意，这个速度得提高，退房五秒，交卡就走。30楼的旋转早餐厅很好，没有人来人往的嘈杂，比较安静，需要等位但是不久，唯一这里让我不太痛快的就是明明鸡蛋里加的料都是我一个个点的，怎么我后面来排队的老黑就先拿了，留我愣在那，然后厨师又重复一遍我要加的东西给我做好，我去国外好像也没得到太多优待吧，国内还被区别？？那我就干脆专找外籍服务生服务吧，两个貌似印度人的员工态度都很好，耐心的帮我拍照，名字忘记了。最后一点，酒店很贴心的送了一大盘水果，可惜，除了火龙果其他的都酸掉牙，采购部门用点心啊', '["https://dimg04.c-ctrip.com/images/0236112000eulqymb5A9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000eulcxzfEC04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000ev060l364BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000euzw2gy1BAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000ev06ryu6092_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-07-22', '花园双床房', '双床房', '朋友出游', 349, 0, 17, 8, '["退房/入住效率","餐饮设施","整体满意度"]'::jsonb, '退房/入住效率', '餐饮设施', '整体满意度'),
('68027ad3e3c98b09417658f5', '房间整洁干净，有宾至如归的感觉，不愧是老牌五星级酒店，尤其是酒店居然有博物馆，给孩子们提供了参观场所', '["https://dimg04.c-ctrip.com/images/0235c12000fzvwausC405_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000fzvhaqz2C2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000fzvkrxh6364_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000fzw1yx10A9A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园大床房', '大床房', '家庭亲子', 50, 0, 10, 7, '["卫生状况","整体满意度","公共设施"]'::jsonb, '卫生状况', '整体满意度', '公共设施'),
('68027ad3e3c98b09417658f6', '这次来广州听取老公意见试试老牌五星酒店，从进酒店开始礼宾到服务员都很热情礼貌，这里要重点谢谢办入住的帅哥Tony 接待热情耐心听我说要新点房间直接就帮我升级粤韵大床房,是我原来订的房型的一倍价格，太nice 了房间是一厅一房特别的舒适。这次入住真的是我来广州住的最舒服的一次，酒店本身就是一个可以逛和参观的地方，它的底蕴真的是其他酒店无法比拟的。', '["https://dimg04.c-ctrip.com/images/0232x12000eunhu8y2C51_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000eune0nwE428_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000eune0ny09BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000eunfpn20965_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000eun6ihvE999_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000eung0d87686_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 173, 0, 4, 9, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68027ad3e3c98b09417658f7', '住了第一晚就开始出疹，痒的要死，一开始没在意，后面越来越厉害，房间也是洗水池脏的要死，房间里设施陈旧，一点都标不起五星酒店的称号，希望大家避雷吧', '["https://dimg04.c-ctrip.com/images/0233d12000fbjju0fF8D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-08-31', '城央绿意双床房', '双床房', '家庭亲子', 72, 0, 2, 8, '["卫生状况","房间设施","整体满意度"]'::jsonb, '卫生状况', '房间设施', '整体满意度'),
('68027ad3e3c98b09417658f8', '每次去广州首选花园酒店，服务态度好，酒店环境好，尤其是酒店一楼的花园老人孩子都喜欢，交通也十分方便？', '["https://dimg04.c-ctrip.com/images/0201i12000fzstjb5C9CE_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236s12000fzsaj8o47B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000fzsb1sbCB16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000fzs3pb0D764_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园双床房', '双床房', '家庭亲子', 50, 0, 1, 6, '["整体满意度","交通便利性","公共设施"]'::jsonb, '整体满意度', '交通便利性', '公共设施'),
('68027ad3e3c98b09417658f9', '地道老广州，粤语服务有味道', '["https://dimg04.c-ctrip.com/images/0234812000h7y1d19F9A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-15', '花园双床房', '双床房', '家庭亲子', 13, 0, 68, 4, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68027ae0e3c98b09417658fa', '服务：Echo,beryle,mira,Cathy非常棒

广州花园酒店设施完善，大堂历史悠久。
大堂非常的富丽堂皇，房间也不错，行政酒廊服务更是没的说，然后广州花园酒店的位置离地铁站也非常的近。然后离北京路，越秀公园，动物园，珠江新城，越秀公园，天河区都挺近的，去广州塔也不远，酒店很棒，尤其要点名表扬酒店三十楼行政酒廊，行政酒廊的小姐姐们，Echo,beryle
,cathy,mira,kitty,gretta,kanchan,她们都非常的贴心，善良，美丽，大方，这次入住体验非常的棒，因为有她们他们每一个小姐姐的笑容都很甜，其中一进来Beryle就热情的接待我们，给我们介绍酒店哪里有好玩好吃的地方，Echo也会非常积极的服务，我们看到什么空的盘子啊都会过来询问我们，然后询问要不要收走。中秋节入住期间，行政酒廊有给我们送了月饼，让我们真情实意的感受到了中秋的氛围。Carrie是一个印度人，他的中文很棒。这都让我们感到非常舒服，你们的服务态度也很好，租个台也很热情，打招呼能感受到30楼的服务意识都很好，看着这一群可爱的小妹妹们的校友，我们用餐的也很开心,我们介绍了酒店的26个打卡点，有博物馆还有后花园的打卡点，因为广州花园酒店有他们，所以过年我也会回来广州花园酒店入住的，希望下次回来入住，还能看见Echo,Carrie,kitty这群小姐姐们
过年见

设施：很棒', '["https://dimg04.c-ctrip.com/images/0236a12000fn0xn783B3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000fn0w5ej6A07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000fn0zefy9939_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000fn0ztwxE8D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000fn0yl6571EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000fn0x7ij7D24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000fn0w5en77F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000fn0yt6qF523_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000fn0vtjtCECB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-19', '花园大床房', '大床房', '情侣出游', 590, 1, 5, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027ae0e3c98b09417658fb', '广州花园酒店环境很好，周围出行也非常方便，出门就是地铁口。一进入大堂，金碧辉煌的壁画映入眼帘，前台宾客关系经理lavinia 零零热情好客，迅速为我办理入住，漂亮温柔的小姐姐！广州花园酒店作为一家已开39年的历史悠久的酒店，房间整体维护还可以，房间水龙头开大的话水会溅出来，建议改进。服务加满分！', '["https://dimg04.c-ctrip.com/images/0235g12000evxcx9r2CB8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000evxcrjb5755_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000evwyphs150C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-24', '花园大床房', '大床房', '商务出差', 148, 0, 6, 8, '["交通便利性","前台服务","房间设施"]'::jsonb, '交通便利性', '前台服务', '房间设施'),
('68027ae0e3c98b09417658fc', '还可以吧，有一些外国人进进出出，空调打的比较冷，后面那个小花园还是比较漂亮，早上打打太极拳很棒！', '["https://dimg04.c-ctrip.com/images/0230812000fzhu39015A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-05', '花园大床房', '大床房', '情侣出游', 48, 0, 18, 5, '["公共设施","房间设施"]'::jsonb, '公共设施', '房间设施', NULL)
 ON CONFLICT (_id) DO NOTHING;
